-- Carlos (finca.loma)
(gen_random_uuid(), 'Ruta del Cafe de Especialidad', 'Recorrido completo por fincas cafeteras de Boquete: desde la semilla hasta la taza. Incluye catacion profesional de cafes de especialidad con puntaje SCA superior a 85.', 'GASTRONOMICA', 4, 'Fincas cafeteras de Palmira, Boquete', 'Chiriqui', 'Boquete', '{}', '{"Guia especialista en cafe","Catacion de 5 variedades","Desayuno tipico","Transporte entre fincas","Bolsa de cafe para llevar"}', '{"Almuerzo","Propinas"}', '{"Ropa comoda","Protector solar","Camara fotografica"}', 0, 15, true, '02ffba96-e3e7-4364-bc4b-22c0946532b0', NOW(), NOW()),

(gen_random_uuid(), 'Ordeno y Vida de Hacienda', 'Experiencia de un dia en hacienda ganadera del interior: ordeno de vacas al amanecer, elaboracion de queso fresco, cabalgata por potreros y almuerzo tipico con fogon de lena.', 'CULTURAL', 6, 'Hacienda Los Pozos, Herrera', 'Herrera', 'Los Pozos', '{}', '{"Ordeno participativo","Taller de queso","Cabalgata 1 hora","Almuerzo tipico con fogon","Guia local"}', '{"Transporte desde la ciudad","Bebidas adicionales"}', '{"Ropa que se pueda ensuciar","Botas o zapatos cerrados"}', 5, 12, true, '02ffba96-e3e7-4364-bc4b-22c0946532b0', NOW(), NOW()),

(gen_random_uuid(), 'Ascenso Nocturno al Volcan Baru', 'Ascenso nocturno al punto mas alto de Panama (3,475 msnm) para ver el amanecer con vista simultanea al oceano Atlantico y Pacifico. Experiencia unica e inolvidable.', 'AVENTURA', 10, 'Parque Nacional Volcan Baru', 'Chiriqui', 'Boquete', '{}', '{"Guia certificado de montana","Linterna frontal","Snacks energeticos","Entrada al parque","Chocolate caliente en la cima"}', '{"Transporte al inicio del sendero","Equipo de camping","Comidas completas"}', '{"Excelente condicion fisica","Botas de senderismo","Ropa termica","Lampara frontal","Mochila con agua 2L"}', 14, 10, true, '02ffba96-e3e7-4364-bc4b-22c0946532b0', NOW(), NOW()),

-- Maria (aventura.chiriqui)
(gen_random_uuid(), 'Rafting Rio Chiriqui Viejo Clase III-IV', 'Descenso de 12 km por los rapidos del Rio Chiriqui Viejo, clasificados entre clase III y IV. Adrenalina pura rodeada de paisajes tropicales de montaña.', 'DEPORTIVA', 4, 'Rio Chiriqui Viejo, entrada por Palmira', 'Chiriqui', 'Boquete', '{}', '{"Equipo completo de rafting","Guia certificado IRF","Chaleco salvavidas","Casco","Transporte ida y vuelta","Frutas y agua"}', '{"Almuerzo","Fotos profesionales ($15 extra)","Propinas"}', '{"Saber nadar","Buena condicion fisica","Ropa que se pueda mojar","Zapatos cerrados para agua"}', 12, 8, true, 'a1516bbc-5bb7-4f45-983a-e20a91be7be4', NOW(), NOW()),

(gen_random_uuid(), 'Avistamiento de Quetzal y Aves del Bosque Nuboso', 'Caminata guiada al amanecer por senderos del bosque nuboso en busca del Quetzal Resplandeciente y mas de 50 especies de aves endemicas de las tierras altas de Panama.', 'NATURALEZA', 5, 'Senderos de Las Nubes, Cerro Punta', 'Chiriqui', 'Cerro Punta', '{}', '{"Guia ornitologico certificado","Binoculares profesionales","Lista de aves","Desayuno de campo","Transporte al sendero"}', '{"Camara con teleobjetivo","Almuerzo"}', '{"Madrugar (salida 5:00 AM)","Ropa oscura sin colores brillantes","Botas de senderismo","Silencio durante el recorrido"}', 8, 8, true, 'a1516bbc-5bb7-4f45-983a-e20a91be7be4', NOW(), NOW()),

(gen_random_uuid(), 'Canopy y Puentes Colgantes en Boquete', 'Circuito de 8 cables de canopy (tirolesa) y 4 puentes colgantes sobre el dosel del bosque tropical. Vistas aereas espectaculares del canon y cascadas.', 'AVENTURA', 3, 'Boquete Tree Trek, Alto Boquete', 'Chiriqui', 'Boquete', '{}', '{"Equipo de seguridad completo","Guias certificados","8 cables de canopy","4 puentes colgantes","Agua y snack"}', '{"Transporte","Almuerzo","Fotos ($10 extra)"}', '{"Peso entre 30-120 kg","Sin vertigo severo","Zapatos cerrados","Ropa comoda"}', 6, 12, true, 'a1516bbc-5bb7-4f45-983a-e20a91be7be4', NOW(), NOW()),

