(gen_random_uuid(), 'Visita Comunidad Embera - Rio Chagres', 'Navegacion en piragua por el Rio Chagres hasta la comunidad indigena Embera Puru. Danza tradicional, artesania en tagua y jagua, y almuerzo tipico indigena.', 'CULTURAL', 7, 'Rio Chagres, Parque Nacional Chagres', 'Panama', 'Chagres', '{}', '{"Transporte desde Ciudad de Panama","Piragua por el rio","Danza Embera","Taller de artesania","Almuerzo tipico","Pintura corporal con jagua"}', '{"Artesanias para compra","Propinas","Bebidas adicionales"}', '{"Traje de bano debajo de la ropa","Protector solar biodegradable","Repelente","Efectivo para artesanias"}', 4, 20, true, 'd145bc4c-6795-4b02-96a1-20b8cc16486a', NOW(), NOW()),

